-- Stage SQL: CCMS_CTR_CLU (Incremental)
-- Location: s3://c108-dev-fpacfsa-final-zone/cnsv/_configs/stg/CCMS_CTR_CLU/incremental/CCMS_CTR_CLU.sql
-- =============================================================================
SELECT * FROM(SELECT DISTINCT ADM_ST_FSA_CD,ADM_CNTY_FSA_CD,CTR_NBR,CTR_SFX_NBR,CLU_NBR,CLU_ID,CTR_DET_ID,CTR_FARM_TR_ID,CLU_ACRG,CRP_ACRE_RENT_RDN_CD,DATA_STAT_CD,CRE_DT,CRE_USER_NM,LAST_CHG_DT,LAST_CHG_USER_NM,SGNP_TYPE_NM,SGNP_SUB_CAT_NM,SGNP_NBR,SGNP_STYPE_AGR_NM,FARM_NBR,TR_NBR,--__CDC_OPERATION CDC_OPER_CD,CDC_OPER_CD,ROW_NUMBER() over ( partition by CLU_IDorder by TBL_PRIORITY ASC, LAST_CHG_DT DESC ) AS row_num_partFROM(SELECT MASTER_CONTRACT.ADMINISTRATIVE_STATE_FSA_CODE ADM_ST_FSA_CD,MASTER_CONTRACT.ADMINISTRATIVE_COUNTY_FSA_CODE ADM_CNTY_FSA_CD,MASTER_CONTRACT.CONTRACT_NUMBER CTR_NBR,CONTRACT_DETAIL.CONTRACT_SUFFIX_NUMBER CTR_SFX_NBR,CONTRACT_COMMON_LAND_UNIT.CLU_NUMBER CLU_NBR,CONTRACT_COMMON_LAND_UNIT.CLU_IDENTIFIER CLU_ID,CONTRACT_COMMON_LAND_UNIT.CONTRACT_DETAIL_IDENTIFIER CTR_DET_ID,CONTRACT_COMMON_LAND_UNIT.CONTRACT_FARM_TRACT_IDENTIFIER CTR_FARM_TR_ID,CONTRACT_COMMON_LAND_UNIT.CLU_ACREAGE CLU_ACRG,CONTRACT_COMMON_LAND_UNIT.crp_acre_rent_reduction_code CRP_ACRE_RENT_RDN_CD,CONTRACT_COMMON_LAND_UNIT.DATA_STATUS_CODE DATA_STAT_CD,CONTRACT_COMMON_LAND_UNIT.CREATION_DATE CRE_DT,CONTRACT_COMMON_LAND_UNIT.CREATION_USER_NAME CRE_USER_NM,CONTRACT_COMMON_LAND_UNIT.LAST_CHANGE_DATE LAST_CHG_DT,CONTRACT_COMMON_LAND_UNIT.LAST_CHANGE_USER_NAME LAST_CHG_USER_NM,SIGNUP_TYPE.SIGNUP_TYPE_NAME SGNP_TYPE_NM,SIGNUP_SUB_CATEGORY.SIGNUP_SUB_CATEGORY_NAME SGNP_SUB_CAT_NM,SIGNUP.signup_number SGNP_NBR,SIGNUP.SIGNUP_SUBTYPE_AGREEMENT_NAME SGNP_STYPE_AGR_NM,CONTRACT_FARM_TRACT.FARM_NUMBER FARM_NBR,CONTRACT_FARM_TRACT.TRACT_NUMBER TR_NBR,--_CDC_OPERATION,CONTRACT_COMMON_LAND_UNIT.op,1 AS TBL_PRIORITYFROM "fsa-{env}-ccms-cdc".CONTRACT_COMMON_LAND_UNIT  LEFT JOIN "fsa-{env}-ccms-cdc".CONTRACT_FARM_TRACT CONTRACT_FARM_TRACT ON (CONTRACT_COMMON_LAND_UNIT.CONTRACT_FARM_TRACT_IDENTIFIER = CONTRACT_FARM_TRACT.CONTRACT_FARM_TRACT_IDENTIFIER)LEFT JOIN "fsa-{env}-ccms-cdc".CONTRACT_DETAIL CONTRACT_DETAIL ON (CONTRACT_DETAIL.CONTRACT_DETAIL_IDENTIFIER = CONTRACT_FARM_TRACT.CONTRACT_DETAIL_IDENTIFIER)LEFT JOIN "fsa-{env}-ccms-cdc".MASTER_CONTRACT MASTER_CONTRACT ON (MASTER_CONTRACT.CONTRACT_IDENTIFIER = CONTRACT_DETAIL.CONTRACT_IDENTIFIER)LEFT JOIN "fsa-{env}-ccms-cdc".SIGNUP SIGNUP ON (SIGNUP.SIGNUP_IDENTIFIER = MASTER_CONTRACT.SIGNUP_IDENTIFIER)LEFT JOIN "fsa-{env}-ccms-cdc".SIGNUP_TYPE SIGNUP_TYPE ON (SIGNUP_TYPE.SIGNUP_TYPE_CODE = SIGNUP.SIGNUP_TYPE_CODE)LEFT JOIN "fsa-{env}-ccms-cdc".SIGNUP_SUB_CATEGORY SIGNUP_SUB_CATEGORY ON (SIGNUP_SUB_CATEGORY.SIGNUP_SUB_CATEGORY_CODE = SIGNUP.SIGNUP_SUB_CATEGORY_CODE)--WHERE __CDC_OPERATION <> 'D'WHERE CONTRACT_COMMON_LAND_UNIT.op <> 'D'
UNIONSELECT MASTER_CONTRACT.ADMINISTRATIVE_STATE_FSA_CODE ADM_ST_FSA_CD,MASTER_CONTRACT.ADMINISTRATIVE_COUNTY_FSA_CODE ADM_CNTY_FSA_CD,MASTER_CONTRACT.CONTRACT_NUMBER CTR_NBR,CONTRACT_DETAIL.CONTRACT_SUFFIX_NUMBER CTR_SFX_NBR,CONTRACT_COMMON_LAND_UNIT.CLU_NUMBER CLU_NBR,CONTRACT_COMMON_LAND_UNIT.CLU_IDENTIFIER CLU_ID,CONTRACT_COMMON_LAND_UNIT.CONTRACT_DETAIL_IDENTIFIER CTR_DET_ID,CONTRACT_COMMON_LAND_UNIT.CONTRACT_FARM_TRACT_IDENTIFIER CTR_FARM_TR_ID,CONTRACT_COMMON_LAND_UNIT.CLU_ACREAGE CLU_ACRG,CONTRACT_COMMON_LAND_UNIT.crp_acre_rent_reduction_code CRP_ACRE_RENT_RDN_CD,CONTRACT_COMMON_LAND_UNIT.DATA_STATUS_CODE DATA_STAT_CD,CONTRACT_COMMON_LAND_UNIT.CREATION_DATE CRE_DT,CONTRACT_COMMON_LAND_UNIT.CREATION_USER_NAME CRE_USER_NM,CONTRACT_COMMON_LAND_UNIT.LAST_CHANGE_DATE LAST_CHG_DT,CONTRACT_COMMON_LAND_UNIT.LAST_CHANGE_USER_NAME LAST_CHG_USER_NM,SIGNUP_TYPE.SIGNUP_TYPE_NAME SGNP_TYPE_NM,SIGNUP_SUB_CATEGORY.SIGNUP_SUB_CATEGORY_NAME SGNP_SUB_CAT_NM,SIGNUP.signup_number SGNP_NBR,SIGNUP.SIGNUP_SUBTYPE_AGREEMENT_NAME SGNP_STYPE_AGR_NM,CONTRACT_FARM_TRACT.FARM_NUMBER FARM_NBR,CONTRACT_FARM_TRACT.TRACT_NUMBER TR_NBR,--__CDC_OPERATION,CONTRACT_DETAIL.op,2 AS TBL_PRIORITYFROM "fsa-{env}-ccms-cdc".CONTRACT_DETAILLEFT JOIN "fsa-{env}-ccms-cdc".CONTRACT_FARM_TRACT CONTRACT_FARM_TRACT ON (CONTRACT_DETAIL.CONTRACT_DETAIL_IDENTIFIER = CONTRACT_FARM_TRACT.CONTRACT_DETAIL_IDENTIFIER)JOIN "fsa-{env}-ccms-cdc".CONTRACT_COMMON_LAND_UNIT CONTRACT_COMMON_LAND_UNIT ON (CONTRACT_COMMON_LAND_UNIT.CONTRACT_FARM_TRACT_IDENTIFIER = CONTRACT_FARM_TRACT.CONTRACT_FARM_TRACT_IDENTIFIER)LEFT JOIN "fsa-{env}-ccms-cdc".MASTER_CONTRACT MASTER_CONTRACT ON (MASTER_CONTRACT.CONTRACT_IDENTIFIER = CONTRACT_DETAIL.CONTRACT_IDENTIFIER)LEFT JOIN "fsa-{env}-ccms-cdc".SIGNUP SIGNUP ON (SIGNUP.SIGNUP_IDENTIFIER = MASTER_CONTRACT.SIGNUP_IDENTIFIER)LEFT JOIN "fsa-{env}-ccms-cdc".SIGNUP_TYPE SIGNUP_TYPE ON (SIGNUP_TYPE.SIGNUP_TYPE_CODE = SIGNUP.SIGNUP_TYPE_CODE)LEFT JOIN "fsa-{env}-ccms-cdc".SIGNUP_SUB_CATEGORY SIGNUP_SUB_CATEGORY ON (SIGNUP_SUB_CATEGORY.SIGNUP_SUB_CATEGORY_CODE = SIGNUP.SIGNUP_SUB_CATEGORY_CODE)--WHERE __CDC_OPERATION <> 'D'WHERE CONTRACT_DETAIL.op <> 'D'
UNIONSELECT MASTER_CONTRACT.ADMINISTRATIVE_STATE_FSA_CODE ADM_ST_FSA_CD,MASTER_CONTRACT.ADMINISTRATIVE_COUNTY_FSA_CODE ADM_CNTY_FSA_CD,MASTER_CONTRACT.CONTRACT_NUMBER CTR_NBR,CONTRACT_DETAIL.CONTRACT_SUFFIX_NUMBER CTR_SFX_NBR,CONTRACT_COMMON_LAND_UNIT.CLU_NUMBER CLU_NBR,CONTRACT_COMMON_LAND_UNIT.CLU_IDENTIFIER CLU_ID,CONTRACT_COMMON_LAND_UNIT.CONTRACT_DETAIL_IDENTIFIER CTR_DET_ID,CONTRACT_COMMON_LAND_UNIT.CONTRACT_FARM_TRACT_IDENTIFIER CTR_FARM_TR_ID,CONTRACT_COMMON_LAND_UNIT.CLU_ACREAGE CLU_ACRG,CONTRACT_COMMON_LAND_UNIT.crp_acre_rent_reduction_code CRP_ACRE_RENT_RDN_CD,CONTRACT_COMMON_LAND_UNIT.DATA_STATUS_CODE DATA_STAT_CD,CONTRACT_COMMON_LAND_UNIT.CREATION_DATE CRE_DT,CONTRACT_COMMON_LAND_UNIT.CREATION_USER_NAME CRE_USER_NM,CONTRACT_COMMON_LAND_UNIT.LAST_CHANGE_DATE LAST_CHG_DT,CONTRACT_COMMON_LAND_UNIT.LAST_CHANGE_USER_NAME LAST_CHG_USER_NM,SIGNUP_TYPE.SIGNUP_TYPE_NAME SGNP_TYPE_NM,SIGNUP_SUB_CATEGORY.SIGNUP_SUB_CATEGORY_NAME SGNP_SUB_CAT_NM,SIGNUP.signup_number SGNP_NBR,SIGNUP.SIGNUP_SUBTYPE_AGREEMENT_NAME SGNP_STYPE_AGR_NM,CONTRACT_FARM_TRACT.FARM_NUMBER FARM_NBR,CONTRACT_FARM_TRACT.TRACT_NUMBER TR_NBR,--__CDC_OPERATION,MASTER_CONTRACT.op,3 AS TBL_PRIORITYFROM "fsa-{env}-ccms-cdc".MASTER_CONTRACTLEFT JOIN "fsa-{env}-ccms-cdc".CONTRACT_DETAIL CONTRACT_DETAIL ON (MASTER_CONTRACT.CONTRACT_IDENTIFIER = CONTRACT_DETAIL.CONTRACT_IDENTIFIER)LEFT JOIN "fsa-{env}-ccms-cdc".CONTRACT_FARM_TRACT CONTRACT_FARM_TRACT ON (CONTRACT_DETAIL.CONTRACT_DETAIL_IDENTIFIER = CONTRACT_FARM_TRACT.CONTRACT_DETAIL_IDENTIFIER)JOIN "fsa-{env}-ccms-cdc".CONTRACT_COMMON_LAND_UNIT CONTRACT_COMMON_LAND_UNIT ON (CONTRACT_COMMON_LAND_UNIT.CONTRACT_FARM_TRACT_IDENTIFIER = CONTRACT_FARM_TRACT.CONTRACT_FARM_TRACT_IDENTIFIER)LEFT JOIN "fsa-{env}-ccms-cdc".SIGNUP SIGNUP ON (SIGNUP.SIGNUP_IDENTIFIER = MASTER_CONTRACT.SIGNUP_IDENTIFIER)LEFT JOIN "fsa-{env}-ccms-cdc".SIGNUP_TYPE SIGNUP_TYPE ON (SIGNUP_TYPE.SIGNUP_TYPE_CODE = SIGNUP.SIGNUP_TYPE_CODE)LEFT JOIN "fsa-{env}-ccms-cdc".SIGNUP_SUB_CATEGORY SIGNUP_SUB_CATEGORY ON (SIGNUP_SUB_CATEGORY.SIGNUP_SUB_CATEGORY_CODE = SIGNUP.SIGNUP_SUB_CATEGORY_CODE)--WHERE __CDC_OPERATION <> 'D'WHERE MASTER_CONTRACT.op <> 'D'
UNIONSELECT MASTER_CONTRACT.ADMINISTRATIVE_STATE_FSA_CODE ADM_ST_FSA_CD,MASTER_CONTRACT.ADMINISTRATIVE_COUNTY_FSA_CODE ADM_CNTY_FSA_CD,MASTER_CONTRACT.CONTRACT_NUMBER CTR_NBR,CONTRACT_DETAIL.CONTRACT_SUFFIX_NUMBER CTR_SFX_NBR,CONTRACT_COMMON_LAND_UNIT.CLU_NUMBER CLU_NBR,CONTRACT_COMMON_LAND_UNIT.CLU_IDENTIFIER CLU_ID,CONTRACT_COMMON_LAND_UNIT.CONTRACT_DETAIL_IDENTIFIER CTR_DET_ID,CONTRACT_COMMON_LAND_UNIT.CONTRACT_FARM_TRACT_IDENTIFIER CTR_FARM_TR_ID,CONTRACT_COMMON_LAND_UNIT.CLU_ACREAGE CLU_ACRG,CONTRACT_COMMON_LAND_UNIT.crp_acre_rent_reduction_code CRP_ACRE_RENT_RDN_CD,CONTRACT_COMMON_LAND_UNIT.DATA_STATUS_CODE DATA_STAT_CD,CONTRACT_COMMON_LAND_UNIT.CREATION_DATE CRE_DT,CONTRACT_COMMON_LAND_UNIT.CREATION_USER_NAME CRE_USER_NM,CONTRACT_COMMON_LAND_UNIT.LAST_CHANGE_DATE LAST_CHG_DT,CONTRACT_COMMON_LAND_UNIT.LAST_CHANGE_USER_NAME LAST_CHG_USER_NM,SIGNUP_TYPE.SIGNUP_TYPE_NAME SGNP_TYPE_NM,SIGNUP_SUB_CATEGORY.SIGNUP_SUB_CATEGORY_NAME SGNP_SUB_CAT_NM,SIGNUP.signup_number SGNP_NBR,SIGNUP.SIGNUP_SUBTYPE_AGREEMENT_NAME SGNP_STYPE_AGR_NM,CONTRACT_FARM_TRACT.FARM_NUMBER FARM_NBR,CONTRACT_FARM_TRACT.TRACT_NUMBER TR_NBR,--__CDC_OPERATION,CONTRACT_FARM_TRACT.op,4 AS TBL_PRIORITYFROM "fsa-{env}-ccms-cdc".CONTRACT_FARM_TRACTJOIN "fsa-{env}-ccms-cdc".CONTRACT_COMMON_LAND_UNIT CONTRACT_COMMON_LAND_UNIT ON (CONTRACT_COMMON_LAND_UNIT.CONTRACT_FARM_TRACT_IDENTIFIER = CONTRACT_FARM_TRACT.CONTRACT_FARM_TRACT_IDENTIFIER)LEFT JOIN "fsa-{env}-ccms-cdc".CONTRACT_DETAIL CONTRACT_DETAIL ON (CONTRACT_DETAIL.CONTRACT_DETAIL_IDENTIFIER = CONTRACT_FARM_TRACT.CONTRACT_DETAIL_IDENTIFIER)LEFT JOIN "fsa-{env}-ccms-cdc".MASTER_CONTRACT MASTER_CONTRACT ON (MASTER_CONTRACT.CONTRACT_IDENTIFIER = CONTRACT_DETAIL.CONTRACT_IDENTIFIER)LEFT JOIN "fsa-{env}-ccms-cdc".SIGNUP SIGNUP ON (SIGNUP.SIGNUP_IDENTIFIER = MASTER_CONTRACT.SIGNUP_IDENTIFIER)LEFT JOIN "fsa-{env}-ccms-cdc".SIGNUP_TYPE SIGNUP_TYPE ON (SIGNUP_TYPE.SIGNUP_TYPE_CODE = SIGNUP.SIGNUP_TYPE_CODE)LEFT JOIN "fsa-{env}-ccms-cdc".SIGNUP_SUB_CATEGORY SIGNUP_SUB_CATEGORY ON (SIGNUP_SUB_CATEGORY.SIGNUP_SUB_CATEGORY_CODE = SIGNUP.SIGNUP_SUB_CATEGORY_CODE)WHERE CONTRACT_FARM_TRACT.op <> 'D'
UNIONSELECT MASTER_CONTRACT.ADMINISTRATIVE_STATE_FSA_CODE ADM_ST_FSA_CD,MASTER_CONTRACT.ADMINISTRATIVE_COUNTY_FSA_CODE ADM_CNTY_FSA_CD,MASTER_CONTRACT.CONTRACT_NUMBER CTR_NBR,CONTRACT_DETAIL.CONTRACT_SUFFIX_NUMBER CTR_SFX_NBR,CONTRACT_COMMON_LAND_UNIT.CLU_NUMBER CLU_NBR,CONTRACT_COMMON_LAND_UNIT.CLU_IDENTIFIER CLU_ID,CONTRACT_COMMON_LAND_UNIT.CONTRACT_DETAIL_IDENTIFIER CTR_DET_ID,CONTRACT_COMMON_LAND_UNIT.CONTRACT_FARM_TRACT_IDENTIFIER CTR_FARM_TR_ID,CONTRACT_COMMON_LAND_UNIT.CLU_ACREAGE CLU_ACRG,CONTRACT_COMMON_LAND_UNIT.crp_acre_rent_reduction_code CRP_ACRE_RENT_RDN_CD,CONTRACT_COMMON_LAND_UNIT.DATA_STATUS_CODE DATA_STAT_CD,CONTRACT_COMMON_LAND_UNIT.CREATION_DATE CRE_DT,CONTRACT_COMMON_LAND_UNIT.CREATION_USER_NAME CRE_USER_NM,CONTRACT_COMMON_LAND_UNIT.LAST_CHANGE_DATE LAST_CHG_DT,CONTRACT_COMMON_LAND_UNIT.LAST_CHANGE_USER_NAME LAST_CHG_USER_NM,SIGNUP_TYPE.SIGNUP_TYPE_NAME SGNP_TYPE_NM,SIGNUP_SUB_CATEGORY.SIGNUP_SUB_CATEGORY_NAME SGNP_SUB_CAT_NM,SIGNUP.signup_number SGNP_NBR,SIGNUP.SIGNUP_SUBTYPE_AGREEMENT_NAME SGNP_STYPE_AGR_NM,CONTRACT_FARM_TRACT.FARM_NUMBER FARM_NBR,CONTRACT_FARM_TRACT.TRACT_NUMBER TR_NBR,SIGNUP.op,5 AS TBL_PRIORITYFROM "fsa-{env}-ccms-cdc".SIGNUPLEFT JOIN "fsa-{env}-ccms-cdc".MASTER_CONTRACT MASTER_CONTRACT ON (SIGNUP.SIGNUP_IDENTIFIER = MASTER_CONTRACT.SIGNUP_IDENTIFIER)LEFT JOIN "fsa-{env}-ccms-cdc".SIGNUP_TYPE SIGNUP_TYPE ON (SIGNUP_TYPE.SIGNUP_TYPE_CODE = SIGNUP.SIGNUP_TYPE_CODE)LEFT JOIN "fsa-{env}-ccms-cdc".SIGNUP_SUB_CATEGORY SIGNUP_SUB_CATEGORY ON (SIGNUP_SUB_CATEGORY.SIGNUP_SUB_CATEGORY_CODE = SIGNUP.SIGNUP_SUB_CATEGORY_CODE)LEFT JOIN "fsa-{env}-ccms-cdc".CONTRACT_DETAIL CONTRACT_DETAIL ON (MASTER_CONTRACT.CONTRACT_IDENTIFIER = CONTRACT_DETAIL.CONTRACT_IDENTIFIER)LEFT JOIN "fsa-{env}-ccms-cdc".CONTRACT_FARM_TRACT CONTRACT_FARM_TRACT ON  (CONTRACT_DETAIL.CONTRACT_DETAIL_IDENTIFIER = CONTRACT_FARM_TRACT.CONTRACT_DETAIL_IDENTIFIER) JOIN "fsa-{env}-ccms-cdc".CONTRACT_COMMON_LAND_UNIT CONTRACT_COMMON_LAND_UNIT ON (CONTRACT_COMMON_LAND_UNIT.CONTRACT_FARM_TRACT_IDENTIFIER = CONTRACT_FARM_TRACT.CONTRACT_FARM_TRACT_IDENTIFIER)WHERE SIGNUP.op <> 'D'
UNIONSELECT MASTER_CONTRACT.ADMINISTRATIVE_STATE_FSA_CODE ADM_ST_FSA_CD,MASTER_CONTRACT.ADMINISTRATIVE_COUNTY_FSA_CODE ADM_CNTY_FSA_CD,MASTER_CONTRACT.CONTRACT_NUMBER CTR_NBR,CONTRACT_DETAIL.CONTRACT_SUFFIX_NUMBER CTR_SFX_NBR,CONTRACT_COMMON_LAND_UNIT.CLU_NUMBER CLU_NBR,CONTRACT_COMMON_LAND_UNIT.CLU_IDENTIFIER CLU_ID,CONTRACT_COMMON_LAND_UNIT.CONTRACT_DETAIL_IDENTIFIER CTR_DET_ID,CONTRACT_COMMON_LAND_UNIT.CONTRACT_FARM_TRACT_IDENTIFIER CTR_FARM_TR_ID,CONTRACT_COMMON_LAND_UNIT.CLU_ACREAGE CLU_ACRG,CONTRACT_COMMON_LAND_UNIT.crp_acre_rent_reduction_code CRP_ACRE_RENT_RDN_CD,CONTRACT_COMMON_LAND_UNIT.DATA_STATUS_CODE DATA_STAT_CD,CONTRACT_COMMON_LAND_UNIT.CREATION_DATE CRE_DT,CONTRACT_COMMON_LAND_UNIT.CREATION_USER_NAME CRE_USER_NM,CONTRACT_COMMON_LAND_UNIT.LAST_CHANGE_DATE LAST_CHG_DT,CONTRACT_COMMON_LAND_UNIT.LAST_CHANGE_USER_NAME LAST_CHG_USER_NM,SIGNUP_TYPE.SIGNUP_TYPE_NAME SGNP_TYPE_NM,SIGNUP_SUB_CATEGORY.SIGNUP_SUB_CATEGORY_NAME SGNP_SUB_CAT_NM,SIGNUP.signup_number SGNP_NBR,SIGNUP.SIGNUP_SUBTYPE_AGREEMENT_NAME SGNP_STYPE_AGR_NM,CONTRACT_FARM_TRACT.FARM_NUMBER FARM_NBR,CONTRACT_FARM_TRACT.TRACT_NUMBER TR_NBR,--__CDC_OPERATION,SIGNUP_TYPE.op,6 AS TBL_PRIORITYFROM "fsa-{env}-ccms-cdc".SIGNUP_TYPELEFT JOIN "fsa-{env}-ccms-cdc".SIGNUP SIGNUP ON (SIGNUP_TYPE.SIGNUP_TYPE_CODE = SIGNUP.SIGNUP_TYPE_CODE)LEFT JOIN "fsa-{env}-ccms-cdc".MASTER_CONTRACT MASTER_CONTRACT ON (SIGNUP.SIGNUP_IDENTIFIER = MASTER_CONTRACT.SIGNUP_IDENTIFIER) LEFT JOIN "fsa-{env}-ccms-cdc".SIGNUP_SUB_CATEGORY SIGNUP_SUB_CATEGORY ON (SIGNUP_SUB_CATEGORY.SIGNUP_SUB_CATEGORY_CODE = SIGNUP.SIGNUP_SUB_CATEGORY_CODE)LEFT JOIN "fsa-{env}-ccms-cdc".CONTRACT_DETAIL CONTRACT_DETAIL ON (MASTER_CONTRACT.CONTRACT_IDENTIFIER = CONTRACT_DETAIL.CONTRACT_IDENTIFIER)LEFT JOIN "fsa-{env}-ccms-cdc".CONTRACT_FARM_TRACT CONTRACT_FARM_TRACT ON  (CONTRACT_DETAIL.CONTRACT_DETAIL_IDENTIFIER = CONTRACT_FARM_TRACT.CONTRACT_DETAIL_IDENTIFIER) JOIN "fsa-{env}-ccms-cdc".CONTRACT_COMMON_LAND_UNIT CONTRACT_COMMON_LAND_UNIT ON (CONTRACT_COMMON_LAND_UNIT.CONTRACT_FARM_TRACT_IDENTIFIER = CONTRACT_FARM_TRACT.CONTRACT_FARM_TRACT_IDENTIFIER)WHERE SIGNUP_TYPE.op <> 'D'
UNIONSELECT MASTER_CONTRACT.ADMINISTRATIVE_STATE_FSA_CODE ADM_ST_FSA_CD,MASTER_CONTRACT.ADMINISTRATIVE_COUNTY_FSA_CODE ADM_CNTY_FSA_CD,MASTER_CONTRACT.CONTRACT_NUMBER CTR_NBR,CONTRACT_DETAIL.CONTRACT_SUFFIX_NUMBER CTR_SFX_NBR,CONTRACT_COMMON_LAND_UNIT.CLU_NUMBER CLU_NBR,CONTRACT_COMMON_LAND_UNIT.CLU_IDENTIFIER CLU_ID,CONTRACT_COMMON_LAND_UNIT.CONTRACT_DETAIL_IDENTIFIER CTR_DET_ID,CONTRACT_COMMON_LAND_UNIT.CONTRACT_FARM_TRACT_IDENTIFIER CTR_FARM_TR_ID,CONTRACT_COMMON_LAND_UNIT.CLU_ACREAGE CLU_ACRG,CONTRACT_COMMON_LAND_UNIT.crp_acre_rent_reduction_code CRP_ACRE_RENT_RDN_CD,CONTRACT_COMMON_LAND_UNIT.DATA_STATUS_CODE DATA_STAT_CD,CONTRACT_COMMON_LAND_UNIT.CREATION_DATE CRE_DT,CONTRACT_COMMON_LAND_UNIT.CREATION_USER_NAME CRE_USER_NM,CONTRACT_COMMON_LAND_UNIT.LAST_CHANGE_DATE LAST_CHG_DT,CONTRACT_COMMON_LAND_UNIT.LAST_CHANGE_USER_NAME LAST_CHG_USER_NM,SIGNUP_TYPE.SIGNUP_TYPE_NAME SGNP_TYPE_NM,SIGNUP_SUB_CATEGORY.SIGNUP_SUB_CATEGORY_NAME SGNP_SUB_CAT_NM,SIGNUP.signup_number SGNP_NBR,SIGNUP.SIGNUP_SUBTYPE_AGREEMENT_NAME SGNP_STYPE_AGR_NM,CONTRACT_FARM_TRACT.FARM_NUMBER FARM_NBR,CONTRACT_FARM_TRACT.TRACT_NUMBER TR_NBR,--__CDC_OPERATION,SIGNUP_SUB_CATEGORY.op,7 AS TBL_PRIORITYFROM "fsa-{env}-ccms-cdc".SIGNUP_SUB_CATEGORYLEFT JOIN "fsa-{env}-ccms-cdc".SIGNUP SIGNUP ON (SIGNUP_SUB_CATEGORY.SIGNUP_SUB_CATEGORY_CODE = SIGNUP.SIGNUP_SUB_CATEGORY_CODE)LEFT JOIN "fsa-{env}-ccms-cdc".MASTER_CONTRACT MASTER_CONTRACT ON (SIGNUP.SIGNUP_IDENTIFIER = MASTER_CONTRACT.SIGNUP_IDENTIFIER)LEFT JOIN "fsa-{env}-ccms-cdc".SIGNUP_TYPE SIGNUP_TYPE ON (SIGNUP_TYPE.SIGNUP_TYPE_CODE = SIGNUP.SIGNUP_TYPE_CODE) LEFT JOIN "fsa-{env}-ccms-cdc".CONTRACT_DETAIL CONTRACT_DETAIL ON (MASTER_CONTRACT.CONTRACT_IDENTIFIER = CONTRACT_DETAIL.CONTRACT_IDENTIFIER)LEFT JOIN "fsa-{env}-ccms-cdc".CONTRACT_FARM_TRACT CONTRACT_FARM_TRACT ON  (CONTRACT_DETAIL.CONTRACT_DETAIL_IDENTIFIER = CONTRACT_FARM_TRACT.CONTRACT_DETAIL_IDENTIFIER) JOIN "fsa-{env}-ccms-cdc".CONTRACT_COMMON_LAND_UNIT CONTRACT_COMMON_LAND_UNIT ON (CONTRACT_COMMON_LAND_UNIT.CONTRACT_FARM_TRACT_IDENTIFIER = CONTRACT_FARM_TRACT.CONTRACT_FARM_TRACT_IDENTIFIER)WHERE SIGNUP_SUB_CATEGORY.op <> 'D') STG_ALL) STG_UNQWHERE row_num_part = 1  AND CONTRACT_COMMON_LAND_UNIT.dart_filedate BETWEEN DATE '{ETL_START_DATE}' AND DATE '{ETL_END_DATE}'

UNIONSELECT DISTINCTNULL ADM_ST_FSA_CD,NULL ADM_CNTY_FSA_CD,NULL CTR_NBR,NULL CTR_SFX_NBR,CONTRACT_COMMON_LAND_UNIT.CLU_NUMBER CLU_NBR,CONTRACT_COMMON_LAND_UNIT.CLU_IDENTIFIER CLU_ID,CONTRACT_COMMON_LAND_UNIT.CONTRACT_DETAIL_IDENTIFIER CTR_DET_ID,CONTRACT_COMMON_LAND_UNIT.CONTRACT_FARM_TRACT_IDENTIFIER CTR_FARM_TR_ID,CONTRACT_COMMON_LAND_UNIT.CLU_ACREAGE CLU_ACRG,CONTRACT_COMMON_LAND_UNIT.crp_acre_rent_reduction_code CRP_ACRE_RENT_RDN_CD,CONTRACT_COMMON_LAND_UNIT.DATA_STATUS_CODE DATA_STAT_CD,CONTRACT_COMMON_LAND_UNIT.CREATION_DATE CRE_DT,CONTRACT_COMMON_LAND_UNIT.CREATION_USER_NAME CRE_USER_NM,CONTRACT_COMMON_LAND_UNIT.LAST_CHANGE_DATE LAST_CHG_DT,CONTRACT_COMMON_LAND_UNIT.LAST_CHANGE_USER_NAME LAST_CHG_USER_NM,NULL SGNP_TYPE_NM,NULL SGNP_SUB_CAT_NM,NULL SGNP_NBR,NULL SGNP_STYPE_AGR_NM,NULL FARM_NBR,NULL TR_NBR,'D' CDC_OPER_CD,1 AS row_num_partFROM "fsa-{env}-ccms-cdc".CONTRACT_COMMON_LAND_UNITWHERE CONTRACT_COMMON_LAND_UNIT.op = 'D'